<script setup lang="ts">

import ChangeTheme from "@/components/layout/ChangeTheme.vue";
import ChangeColor from "@/components/layout/ChangeColor.vue";
import Button from "@/components/common/Button.vue";
import {onMounted, ref, watch, watchEffect} from "vue";
import {useLayoutStore} from "@/stores/layout.ts";

const closeSwiper = ref(false)
const closeSakura = ref(false)
const layout = useLayoutStore()
const changeBc = (type: string) => {
  switch (type) {
    case "swiper":
      layout.state.swiper = true
      localStorage.setItem('swiper', JSON.stringify(layout.state.swiper))
      break
    case "pure":
      layout.state.swiper = false
      localStorage.setItem('swiper', JSON.stringify(layout.state.swiper))
      break
    default:
      break
  }
}
const scToTop = () => {
  window.scrollTo({
    top: 0,
    behavior: "smooth",
  })
}
watch(closeSakura, (newVal) => {
  if (newVal) {
    layout.state.isSnowShow = false
    localStorage.setItem('sakura', JSON.stringify(layout.state.isSnowShow))
  } else {
    layout.state.isSnowShow = true
    localStorage.setItem('sakura', JSON.stringify(layout.state.isSnowShow))
  }
  layout.state.isSnowShow = JSON.parse(localStorage.getItem('sakura') as string)
})
onMounted(() => {
  if (localStorage.getItem('swiper')) {
    layout.state.swiper = JSON.parse(localStorage.getItem('swiper') as string)
  }
  if (localStorage.getItem('sakura')) {
    layout.state.isSnowShow = JSON.parse(localStorage.getItem('sakura') as string)
  }
})
</script>

